BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?pkg vocab:NamedElement_name "Wavefront%20Calibration%20Lookup%20Table" .
  ?pkg vocab:Element_ownedElement ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?pkg vocab:NamedElement_name "Wavefront%20Calibration%20Lookup%20Table" .
  ?pkg vocab:Package_packagedElement ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?pkg vocab:NamedElement_name "Wavefront%20Calibration%20Lookup%20Table" .
  ?elem vocab:Element_owner ?pkg .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?qualifiedName WHERE {
  ?elem vocab:NamedElement_name ?name . 
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Wavefront%20Calibration%20Lookup%20Table")))
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
}
LIMIT 25
